object LoggingManager {
    private lateinit var loggingSystem: ProductionLoggingSystem
    lateinit var authLogger: AuthenticationLogger
    lateinit var dbLogger: DatabaseLogger
    lateinit var apiLogger: ApiLogger

    fun initialize(context: Context) {
        loggingSystem = ProductionLoggingSystem(context)
        authLogger = AuthenticationLogger(loggingSystem)
        dbLogger = DatabaseLogger(loggingSystem)
        apiLogger = ApiLogger(loggingSystem)
    }

    fun logException(exception: Throwable, context: String? = null, additionalData: Map<String, Any?>? = null) {
        loggingSystem.logException(exception, context, additionalData)
    }

    fun exportLogs(): List<File> = loggingSystem.exportLogs()

